Implementasi Observer Pattern menggunakan Abstract Base Class (ABC) untuk enforce interface yang ketat. Kode ini dirancang untuk skalabilitas dan handling error dasar agar satu observer yang gagal tidak menjatuhkan seluruh sistem.

```python
from abc import ABC, abstractmethod
from typing import List, Any
import logging

# Konfigurasi Logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger("ObserverPattern")

class IObserver(ABC):
    @abstractmethod
    def update(self, data: Any) -> None:
        pass

class ISubject(ABC):
    @abstractmethod
    def attach(self, observer: IObserver) -> None:
        pass

    @abstractmethod
    def detach(self, observer: IObserver) -> None:
        pass

    @abstractmethod
    def notify(self, data: Any) -> None:
        pass

class ConcreteSubject(ISubject):
    def __init__(self):
        self._observers: List[IObserver] = []

    def attach(self, observer: IObserver) -> None:
        if observer not in self._observers:
            self._observers.append(observer)
            logger.info("Observer attached successfully.")

    def detach(self, observer: IObserver) -> None:
        if observer in self._observers:
            self._observers.remove(observer)
            logger.info("Observer detached successfully.")

    def notify(self, data: Any) -> None:
        # Validasi data sebelum didistribusikan (Security Best Practice)
        if not isinstance(data, dict):
            logger.warning("Data format unexpected. Expecting dict.")
            return

        for observer in self._observers:
            try:
                observer.update(data)
            except Exception as e:
                # Isolasi error agar satu observer rusak tidak menghentikan notifikasi ke lainnya
                logger.error(f"Error notifying observer {observer.__class__.__name__}: {e}")

class ConcreteObserver(IObserver):
    def __init__(self, name: str):
        self.name = name

    def update(self, data: Any) -> None:
        # Proses data dengan asumsi data sudah sanitized oleh Subject
        logger.info(f"{self.name} received data: {data}")

# Usage Example
if __name__ == "__main__":
    subject = ConcreteSubject()
    obs1 = ConcreteObserver("SecurityMonitor")
    obs2 = ConcreteObserver("LogAnalyzer")

    subject.attach(obs1)
    subject.attach(obs2)

    # Data harus divalidasi sebelum di-notify
    subject.notify({"event": "login_attempt", "status": "success", "ip": "192.168.1.1"})
```

### Catatan Teknis & Keamanan:

1.  **Isolasi Error:** Blok `try-except` di dalam `notify` wajib ada. Jika observer melakukan query DB yang gagal atau timeout, subject tetap stabil.
2.  **Validasi Data:** Pastikan data yang passed ke `notify` sudah sanitized. Jangan pernah melewatkan input user mentah langsung ke observer jika observer tersebut melakukan eksekusi query atau command.
3.  **Thread Safety:** Implementasi di atas belum thread-safe. Jika digunakan dalam environment multithreading (seperti worker server), bungkus operasi list `_observers` dengan `threading.Lock`.
4.  **Memory Leak:** Pastikan observer di-`detach` saat tidak digunakan lagi (misal: saat session user berakhir) untuk mencegah object tertahan di memori.

PERINGATAN KEAMANAN: **Jangan pernah menggunakan `eval()` bawaan Python** untuk memproses input pengguna. Itu adalah celah keamanan kritis (Remote Code Execution/RCE) yang memungkinkan penyerang menjalankan perintah sistem arbitrer di server Anda.

Gunakan modul `ast` (Abstract Syntax Tree) untuk parsing ekspresi matematika secara aman dengan membatasi operator yang diizinkan.

Berikut implementasi aman menggunakan `ast.NodeVisitor`:

```python
import ast
import operator

class SafeMathEvaluator(ast.NodeVisitor):
    """Parser aman untuk ekspresi matematika dasar."""

    OPERATORS = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
    }

    def visit_Expression(self, node):
        return self.visit(node.body)

    def visit_BinOp(self, node):
        if type(node.op) not in self.OPERATORS:
            raise ValueError(f"Operator tidak diizinkan: {type(node.op).__name__}")
        left = self.visit(node.left)
        right = self.visit(node.right)
        return self.OPERATORS[type(node.op)](left, right)

    def visit_UnaryOp(self, node):
        if type(node.op) not in self.OPERATORS:
            raise ValueError(f"Operator unary tidak diizinkan: {type(node.op).__name__}")
        operand = self.visit(node.operand)
        return self.OPERATORS[type(node.op)](operand)

    def visit_Constant(self, node):
        if isinstance(node.value, (int, float)):
            return node.value
        raise ValueError("Hanya angka (int/float) yang diizinkan")

    # Support untuk Python < 3.8
    def visit_Num(self, node):
        return self.visit_Constant(node)

    def generic_visit(self, node):
        raise ValueError(f"Ekspresi tidak aman terdeteksi: {type(node).__name__}")

def safe_math_eval(expression: str) -> float | int:
    """
    Mengevaluasi string ekspresi matematika secara aman.
    Raise ValueError jika ekspresi mengandung kode berbahaya.
    """
    try:
        tree = ast.parse(expression, mode='eval')
        evaluator = SafeMathEvaluator()
        return evaluator.visit(tree)
    except Exception as e:
        raise ValueError(f"Invalid expression: {e}")

# Contoh Penggunaan
if __name__ == "__main__":
    try:
        print(safe_math_eval("2 + 2 * 5"))       # Output: 12
        print(safe_math_eval("10 / (2 + 3)"))    # Output: 2.0
        # print(safe_math_eval("__import__('os').system('ls')"))  # Akan raise ValueError
    except ValueError as e:
        print(f"Error: {e}")
```

### Analisis Teknis:
1.  **Whitelisting Operator**: Hanya operator matematika standar (`+`, `-`, `*`, `/`, `**`, dll.) yang dipetakan. Fungsi bawaan atau import modul diblokir oleh `generic_visit`.
2.  **Tipe Data**: Hanya `int` dan `float` yang diizinkan pada `visit_Constant`. String atau tipe lain akan ditolak.
3.  **Mode Parse**: Menggunakan `mode='eval'` memastikan input adalah ekspresi tunggal, bukan blok kode program.

Gunakan fungsi ini untuk kalkulator, validasi input formulir, atau logika bisnis yang membutuhkan input matematika dari pengguna. Pastikan selalu validasi input di sisi server meskipun ada validasi di sisi klien.

Berikut implementasi fungsi Python untuk membandingkan dua dictionary secara recursif. Fungsi ini mengembalikan struktur yang jelas untuk key yang `added`, `removed`, dan `changed`.

```python
def diff_dicts(d1, d2, path=""):
    """
    Membandingkan dua dictionary secara recursif.
    Returns: dict dengan key 'added', 'removed', 'changed'.
    """
    diff = {
        'added': {},
        'removed': {},
        'changed': {}
    }

    # Cek key yang ada di d1 tapi tidak di d2 (Removed)
    for key in d1:
        if key not in d2:
            diff['removed'][key] = d1[key]
        else:
            val1 = d1[key]
            val2 = d2[key]

            # Jika keduanya dictionary, lakukan rekursi
            if isinstance(val1, dict) and isinstance(val2, dict):
                nested_diff = diff_dicts(val1, val2, f"{path}.{key}")

                # Merge hasil recursi jika ada perubahan
                if nested_diff['added'] or nested_diff['removed'] or nested_diff['changed']:
                    diff['changed'][key] = nested_diff
            # Jika nilai berbeda
            elif val1 != val2:
                diff['changed'][key] = {"old": val1, "new": val2}

    # Cek key yang ada di d2 tapi tidak di d1 (Added)
    for key in d2:
        if key not in d1:
            diff['added'][key] = d2[key]

    return diff

# Contoh Usage
if __name__ == "__main__":
    dict_a = {
        "server": {
            "ip": "192.168.1.1",
            "port": 8080,
            "ssl": True
        },
        "debug": False
    }

    dict_b = {
        "server": {
            "ip": "192.168.1.2", # Changed
            "port": 8080,
            "timeout": 30        # Added
        },
        "debug": False,
        "log_level": "INFO"      # Added
    }

    import json
    result = diff_dicts(dict_a, dict_b)
    print(json.dumps(result, indent=2))
```

### Catatan Teknis:
1.  **Kompleksitas**: O(N + M) dimana N dan M adalah jumlah key pada masing-masing dictionary.
2.  **Tipe Data**: Fungsi ini secara spesifik menangani nested `dict`. Untuk list atau tipe data kompleks lainnya, perlu penyesuaian logika perbandingan (deep equal).
3.  **Keamanan**: Pastikan input dictionary tidak mengandung objek yang tidak dapat diserialisasi jika hasilnya akan diproses lebih lanjut (misalnya dikirim ke API atau log).

Gunakan ini untuk audit konfigurasi atau validasi state sistem. Jika ada pertanyaan terkait integrasi server, tanyakan langsung.
